def get_customer_spending(env: Environment, customer_id: int) -> dict:
    customer = next((c for c in env.customers if c.customer_id == customer_id), None)
    if customer:
        return {'total_spent': sum(p.price for p in customer.purchases)}
    return {'total_spent': 0}

def get_vendor_products(env: Environment, vendor_id: int) -> dict:
    vendor = next((v for v in env.vendors if v.vendor_id == vendor_id), None)
    if vendor:
        return {'products': [p for p in env.products if p.vendor_id == vendor_id]}
    return {'products': []}
